const orgs = $input.all().map(i => i.json);
if (!orgs.length) throw new Error('Org bulunamadı — ORG_ID veya status kontrol et');
const org = orgs[0];
const crm = typeof org.crm_config === 'string' ? JSON.parse(org.crm_config) : (org.crm_config || {});
const persona = typeof org.ai_persona === 'string' ? JSON.parse(org.ai_persona) : (org.ai_persona || {});
const cfg = $('Config').first().json;
return [{ json: {
  orgId:       org.id,
  orgName:     org.name,
  orgTimezone: org.timezone || 'Europe/Berlin',
  agentName:   persona.persona_name || 'Asistan',
  locationId:  crm.location_id,
  pitToken:    crm.pit_token,
  excludedPhones: Array.isArray(org.excluded_phones) ? org.excluded_phones : [],
  SUPABASE_URL:         cfg.SUPABASE_URL,
  SUPABASE_SERVICE_KEY: cfg.SUPABASE_SERVICE_KEY,
  HOUR_START:           cfg.HOUR_START,
  HOUR_END:             cfg.HOUR_END,
  TOUCH2_DELAY_DAYS:    cfg.TOUCH2_DELAY_DAYS,
  CLEANUP_DELAY_DAYS:   cfg.CLEANUP_DELAY_DAYS
}}];

const org = $input.first().json;
const now = new Date();
const tz = org.orgTimezone || 'Europe/Berlin';
const local = new Date(now.toLocaleString('en-US', { timeZone: tz }));
const hour = local.getHours();
const day  = local.getDay(); // 0=Sun, 6=Sat
const allowed = !(day === 0 || day === 6 || hour < org.HOUR_START || hour >= org.HOUR_END);
return [{ json: { ...org, allowed, bhReason: allowed ? null : `Outside hours (${tz} ${hour}:xx, day ${day})` } }];

const org = $input.first().json;
const { orgId, pitToken, agentName, locationId, SUPABASE_URL, SUPABASE_SERVICE_KEY, TOUCH2_DELAY_DAYS, CLEANUP_DELAY_DAYS, excludedPhones } = org;
const h = {
  'apikey': SUPABASE_SERVICE_KEY,
  'Authorization': `Bearer ${SUPABASE_SERVICE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};
const norm = (p) => String(p || '').replace(/\D/g, '');
const excl = new Set((excludedPhones || []).map(norm).filter(Boolean));

// 1. Candidate leads (new + import, not yet outreached)
const leadsRes = await fetch(
  `${SUPABASE_URL}/rest/v1/leads?organization_id=eq.${orgId}&status=eq.new&source_channel=eq.import&select=id,contact_id,collected_data,contacts(phone,full_name)&order=created_at.asc&limit=15`,
  { headers: h }
);
const leads = await leadsRes.json();

// 2. Pick first eligible (no cold_outreach_started, not excluded)
let el = null;
for (const l of (Array.isArray(leads) ? leads : [])) {
  const d = typeof l.collected_data === 'string' ? JSON.parse(l.collected_data) : (l.collected_data || {});
  if (d.cold_outreach_started) continue;
  const phone = l.contacts?.phone;
  if (!phone || excl.has(norm(phone))) continue;
  el = { ...l, phone, name: l.contacts?.full_name || '' };
  break;
}
if (!el) return [{ json: { ...org, phase1: 'no_eligible_lead' } }];

// 3. Fetch touch_1 template
const tplRes = await fetch(
  `${SUPABASE_URL}/rest/v1/outreach_templates?organization_id=eq.${orgId}&sequence_stage=eq.touch_1&channel=eq.whatsapp&active=eq.true&limit=1`,
  { headers: h }
);
const tpls = await tplRes.json();
if (!Array.isArray(tpls) || !tpls.length) return [{ json: { ...org, phase1: 'no_template' } }];

const firstName = (el.name || '').split(' ')[0] || 'Hallo';
const msg = tpls[0].message
  .replace(/\{\{name\}\}/g, firstName)
  .replace(/\{\{agent_name\}\}/g, agentName || 'Asistan');

// 4. GHL: find contact by phone
const srchRes = await fetch(
  `https://services.leadconnectorhq.com/contacts/search?locationId=${locationId}&query=${encodeURIComponent(el.phone)}`,
  { headers: { 'Authorization': `Bearer ${pitToken}`, 'Version': '2021-04-15' } }
);
const srchData = await srchRes.json();
const ghlContacts = srchData.contacts || [];
if (!ghlContacts.length) return [{ json: { ...org, phase1: 'not_in_ghl', phone: el.phone } }];
const ghlContactId = ghlContacts[0].id;

// 5. Send WA message via WAGHL (type: SMS)
await fetch('https://services.leadconnectorhq.com/conversations/messages', {
  method: 'POST',
  headers: { 'Authorization': `Bearer ${pitToken}`, 'Version': '2021-04-15', 'Content-Type': 'application/json' },
  body: JSON.stringify({ type: 'SMS', contactId: ghlContactId, message: msg })
});

// 6. Mark outreach started in Supabase
const now = new Date().toISOString();
await fetch(`${SUPABASE_URL}/rest/v1/leads?id=eq.${el.id}`, {
  method: 'PATCH', headers: h,
  body: JSON.stringify({ collected_data: { cold_outreach_started: now, cold_touch1_sent_at: now } })
});

// 7. Schedule touch_2
await fetch(`${SUPABASE_URL}/rest/v1/follow_up_tasks`, {
  method: 'POST', headers: h,
  body: JSON.stringify({
    organization_id: orgId, lead_id: el.id, contact_id: el.contact_id,
    task_type: 'cold_outreach', template_key: 'touch_2', status: 'pending',
    scheduled_at: new Date(Date.now() + Number(TOUCH2_DELAY_DAYS) * 86400000).toISOString(),
    variables: { ghl_contact_id: ghlContactId, phone: el.phone, name: el.name, agent_name: agentName }
  })
});

// 8. Schedule cleanup check
await fetch(`${SUPABASE_URL}/rest/v1/follow_up_tasks`, {
  method: 'POST', headers: h,
  body: JSON.stringify({
    organization_id: orgId, lead_id: el.id, contact_id: el.contact_id,
    task_type: 'cold_outreach', template_key: 'cleanup', status: 'pending',
    scheduled_at: new Date(Date.now() + (Number(TOUCH2_DELAY_DAYS) + Number(CLEANUP_DELAY_DAYS)) * 86400000).toISOString(),
    variables: { lead_id: el.id }
  })
});

return [{ json: { ...org, phase1: 'sent', leadId: el.id, name: el.name, phone: el.phone, ghlContactId } }];

const org = $input.first().json;
const { orgId, pitToken, agentName, SUPABASE_URL, SUPABASE_SERVICE_KEY } = org;
const h = {
  'apikey': SUPABASE_SERVICE_KEY,
  'Authorization': `Bearer ${SUPABASE_SERVICE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

// Fetch due pending tasks
const tasksRes = await fetch(
  `${SUPABASE_URL}/rest/v1/follow_up_tasks?organization_id=eq.${orgId}&task_type=eq.cold_outreach&status=eq.pending&scheduled_at=lte.${new Date().toISOString()}&order=scheduled_at.asc&limit=10`,
  { headers: h }
);
const tasks = await tasksRes.json();
if (!Array.isArray(tasks) || !tasks.length) return [{ json: { ...org, phase2: 'no_tasks' } }];

let processed = 0;
for (const task of tasks) {
  const vars = typeof task.variables === 'string' ? JSON.parse(task.variables) : (task.variables || {});
  const { ghl_contact_id, phone, name, agent_name } = vars;

  // Check if contact already replied (conversation exists)
  const convRes = await fetch(
    `${SUPABASE_URL}/rest/v1/conversations?organization_id=eq.${orgId}&contact_id=eq.${task.contact_id}&select=id&limit=1`,
    { headers: h }
  );
  const convs = await convRes.json();
  if (Array.isArray(convs) && convs.length > 0) {
    // Engaged — cancel all remaining cold tasks for this lead
    await fetch(
      `${SUPABASE_URL}/rest/v1/follow_up_tasks?lead_id=eq.${task.lead_id}&task_type=eq.cold_outreach&status=eq.pending`,
      { method: 'PATCH', headers: h, body: JSON.stringify({ status: 'cancelled' }) }
    );
    processed++;
    continue;
  }

  if (task.template_key === 'touch_2') {
    const tplRes = await fetch(
      `${SUPABASE_URL}/rest/v1/outreach_templates?organization_id=eq.${orgId}&sequence_stage=eq.touch_2&channel=eq.whatsapp&active=eq.true&limit=1`,
      { headers: h }
    );
    const tpls = await tplRes.json();
    if (Array.isArray(tpls) && tpls.length) {
      const firstName = (name || '').split(' ')[0] || 'Hallo';
      const msg = tpls[0].message
        .replace(/\{\{name\}\}/g, firstName)
        .replace(/\{\{agent_name\}\}/g, agent_name || agentName || 'Asistan');
      await fetch('https://services.leadconnectorhq.com/conversations/messages', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${pitToken}`, 'Version': '2021-04-15', 'Content-Type': 'application/json' },
        body: JSON.stringify({ type: 'SMS', contactId: ghl_contact_id, message: msg })
      });
    }
    await fetch(`${SUPABASE_URL}/rest/v1/follow_up_tasks?id=eq.${task.id}`, {
      method: 'PATCH', headers: h, body: JSON.stringify({ status: 'sent' })
    });

  } else if (task.template_key === 'cleanup') {
    // No reply after touch_2 → mark lead lost
    await fetch(`${SUPABASE_URL}/rest/v1/leads?id=eq.${task.lead_id}`, {
      method: 'PATCH', headers: h, body: JSON.stringify({ status: 'lost' })
    });
    await fetch(
      `${SUPABASE_URL}/rest/v1/follow_up_tasks?lead_id=eq.${task.lead_id}&task_type=eq.cold_outreach&status=eq.pending`,
      { method: 'PATCH', headers: h, body: JSON.stringify({ status: 'cancelled' }) }
    );
  }
  processed++;
}

return [{ json: { ...org, phase2: 'done', processed, total: tasks.length } }];
